import { useState,useEffect } from "react";
import { DragDropContext, Droppable, Draggable } from "@hello-pangea/dnd";
import  axios  from 'axios';
export default function Index(){
    const [data,setData] = useState([]);
    const getData = async () => {
        const res = await axios.get("http://localhost:3003");
        setData(res.data);
        
    }
    useEffect(() => {
        console.log(data);
        getData();
    },[]);
    const todo = data.filter(t => t.statut === "todo");
    const inProgress = data.filter(t => t.statut === "in_progress");
    const done = data.filter(t => t.statut === "done");

    const handleDragEnd = (result) => {
    const { destination, source, draggableId } = result;
    if (!destination) return;

    const newTasks = Array.from(data);
    const movedTask = newTasks.find(t => t.id === draggableId);
    movedTask.statut = destination.droppableId;
    setData(newTasks);
    };
    
    return (
        <>
       <center>
            <div className="kanban">
    <div className="column">
        <h3>À faire</h3>
        {todo.map(t => (
        <div key={t.id} className="task">
            <h4>{t.titre}</h4>
            <p>{t.description}</p>
        </div>
        ))}
    </div>

    <div className="column">
        <h3>En cours</h3>
        {inProgress.map(t => (
        <div key={t.id} className="task">
            <h4>{t.titre}</h4>
            <p>{t.description}</p>
        </div>
        ))}
    </div>

    <div className="column">
        <h3>Terminé</h3>
        {done.map(t => (
        <div key={t.id} className="task">
            <h4>{t.titre}</h4>
            <p>{t.description}</p>
        </div>
        ))}
    </div>
    </div>
       </center>
        </>
    )
}
